// Helper function for quicksort comparison
int cmp(const void *a, const void *b) {
    long long val_a = *(long long*)a;
    long long val_b = *(long long*)b;
    if (val_a < val_b) return -1;
    if (val_a > val_b) return 1;
    return 0;
}

// Helper function to safely get absolute values for long long
long long abs_ll(long long x) {
    return x < 0 ? -x : x;
}

int findMinimumSumDifference(int* inputNumbers, int size) {
    int n = size / 2;
    long long total_sum = 0;

    for (int i = 0; i < size; i++) {
        total_sum += inputNumbers[i];
    }

    // Maximum n is 15. 
    // Max subsets of size k from a set of size 15 is 15C7 = 6435.
    // 6450 is a safe size dimension limit.
    long long L_sums[16][6450];
    int L_counts[16] = {0};

    long long R_sums[16][6450];
    int R_counts[16] = {0};

    // Divide the array into two halves
    int *A = inputNumbers;
    int *B = inputNumbers + n;

    // 1. Generate all subset sums for both halves (Meet-in-the-Middle)
    int num_subsets = 1 << n;
    for (int mask = 0; mask < num_subsets; mask++) {
        int k = 0;
        long long sumA = 0, sumB = 0;
        int temp = mask;

        for (int i = 0; i < n; i++) {
            if (temp & 1) {
                sumA += A[i];
                sumB += B[i];
                k++;
            }
            temp >>= 1;
        }

        L_sums[k][L_counts[k]++] = sumA;
        R_sums[k][R_counts[k]++] = sumB;
    }

    // 2. Sort the right-half sums to prepare for binary search
    for (int i = 0; i <= n; i++) {
        if (R_counts[i] > 0) {
            qsort(R_sums[i], R_counts[i], sizeof(long long), cmp);
        }
    }

    long long min_diff = -1;

    // 3. Binary search for the closest matching sum to complete exactly 'n' elements
    for (int k = 0; k <= n; k++) {
        int r_k = n - k; // Target size from the right half to make exactly n elements

        for (int i = 0; i < L_counts[k]; i++) {
            long long x = L_sums[k][i];

            // Ideal match: total_sum / 2.
            // So we need y such that x + y is as close to (total_sum / 2) as possible.
            long long target = (total_sum / 2) - x;

            int left = 0, right = R_counts[r_k] - 1;
            int best_idx = -1;

            // Binary search the closest value to target in R_sums
            while (left <= right) {
                int mid = left + (right - left) / 2;
                if (R_sums[r_k][mid] == target) {
                    best_idx = mid;
                    break;
                } else if (R_sums[r_k][mid] < target) {
                    best_idx = mid; // Potential lower-bound best
                    left = mid + 1;
                } else {
                    right = mid - 1;
                }
            }

            // Check the lower-bound closest option
            if (best_idx >= 0 && best_idx < R_counts[r_k]) {
                long long y = R_sums[r_k][best_idx];
                long long diff = abs_ll(total_sum - 2 * (x + y));
                if (min_diff == -1 || diff < min_diff) {
                    min_diff = diff;
                }
            }

            // Check the upper-bound closest option (best_idx + 1)
            if (best_idx + 1 >= 0 && best_idx + 1 < R_counts[r_k]) {
                long long y = R_sums[r_k][best_idx + 1];
                long long diff = abs_ll(total_sum - 2 * (x + y));
                if (min_diff == -1 || diff < min_diff) {
                    min_diff = diff;
                }
            }
        }
    }

    // Cast explicitly back to int as maximum difference falls safely within 32-bit int 
    return (int)min_diff;
}

