public static int findMinimumSumDifference(int[] inputNumbers) {
       int n = inputNumbers.length / 2;
       int[] left = new int[n];
       int[] right = new int[n];
       System.arraycopy(inputNumbers, 0, left, 0, n);
       System.arraycopy(inputNumbers, n, right, 0, n);
       int totalSum = 0;
       for (int v : inputNumbers) totalSum += v;
       int half = totalSum / 2;

       java.util.Map<Integer, java.util.ArrayList<Integer>> leftMap = new java.util.HashMap<>();
       java.util.Map<Integer, java.util.ArrayList<Integer>> rightMap = new java.util.HashMap<>();

       for (int mask = 0; mask < (1 << n); mask++) {
           int count = Integer.bitCount(mask);
           int sumLeft = 0;
           for (int i = 0; i < n; i++) {
               if ((mask & (1 << i)) != 0) sumLeft += left[i];
           }
           leftMap.computeIfAbsent(count, k -> new java.util.ArrayList<>()).add(sumLeft);
       }

       for (int mask = 0; mask < (1 << n); mask++) {
           int count = Integer.bitCount(mask);
           int sumRight = 0;
           for (int i = 0; i < n; i++) {
               if ((mask & (1 << i)) != 0) sumRight += right[i];
           }
           rightMap.computeIfAbsent(count, k -> new java.util.ArrayList<>()).add(sumRight);
       }

       for (java.util.ArrayList<Integer> list : leftMap.values()) java.util.Collections.sort(list);
       for (java.util.ArrayList<Integer> list : rightMap.values()) java.util.Collections.sort(list);

       int result = Integer.MAX_VALUE;
       for (int k = 0; k <= n; k++) {
           java.util.ArrayList<Integer> leftList = leftMap.get(k);
           java.util.ArrayList<Integer> rightList = rightMap.get(n - k);
           for (int sumL : leftList) {
               int target = half - sumL;
               int pos = java.util.Collections.binarySearch(rightList, target);
               if (pos < 0) pos = -pos - 1;
               if (pos < rightList.size()) {
                   int sumR = rightList.get(pos);
                   int diff = Math.abs(totalSum - 2 * (sumL + sumR));
                   if (diff < result) result = diff;
               }
               if (pos > 0) {
                   int sumR = rightList.get(pos - 1);
                   int diff = Math.abs(totalSum - 2 * (sumL + sumR));
                   if (diff < result) result = diff;
               }
           }
       }
       return result;
   }

